import React, { useState, useEffect, useCallback } from 'react';
import {
  Container,
  Typography,
  Button,
  Box,
  TextField,
  Rating,
  List,
  ListItem,
  ListItemText,
  Divider,
  Checkbox,
  FormControlLabel
} from '@mui/material';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../services/api';
import { useAuth } from '../context/AuthContext';
import CourseChat from '../components/CourseChat';

const CourseDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [course, setCourse] = useState(null);
  const { user, refreshUser } = useAuth();
  const [rating, setRating] = useState(0);
  const [review, setReview] = useState('');
  const [newMaterial, setNewMaterial] = useState({
    title: '',
    type: 'video',
    url: '',
    content: ''
  });
  const [gradeInputs, setGradeInputs] = useState({});

  const fetchCourse = useCallback(async () => {
    try {
      const response = await api.get(`/courses/${id}`);
      setCourse(response.data);

      // Prepare grading inputs for teacher
      const gradeMap = {};
      (response.data.grades || []).forEach((g) => {
        gradeMap[g.student._id] = { grade: g.grade || '', feedback: g.feedback || '' };
      });
      setGradeInputs(gradeMap);
    } catch (error) {
      console.error('Error fetching course:', error);
    }
  }, [id]);

  useEffect(() => {
    fetchCourse();
  }, [fetchCourse]);

  const handleRatingSubmit = async () => {
    try {
      await api.post(`/courses/${id}/rate`, { rating, review });
      alert('Rating submitted successfully!');
      fetchCourse();
    } catch (error) {
      alert('Failed to submit rating: ' + error.response?.data?.message);
    }
  };

  if (!course) return <div>Loading...</div>;

  const userEnrollment = (user?.enrolledCourses || []).find(
    (enrolled) =>
      (enrolled.course && enrolled.course._id === course._id) ||
      enrolled.course === course._id
  );
  const completedLessons = userEnrollment?.completedLessons || [];
  const isApproved = userEnrollment?.status === 'approved';
  const isPending = userEnrollment?.status === 'pending';
  const isInstructor = user?.id === course.instructor._id;
  const isAdmin = user?.role === 'admin';

  const canAccessLessons = isApproved || isInstructor || isAdmin;

  const pendingEnrollments = course.enrolledStudents.filter(
    (student) => student.status === 'pending'
  );

  const handleToggleLesson = async (lesson) => {
    if (!userEnrollment) return;

    const isCompleted = completedLessons.some(
      (id) => id === lesson._id || id?.toString() === lesson._id
    );

    try {
      await api.put(`/courses/${id}/progress`, {
        lessonId: lesson._id,
        completed: !isCompleted,
      });
      await refreshUser();
      fetchCourse();
    } catch (error) {
      alert('Could not update progress: ' + error.response?.data?.message);
    }
  };

  const handleGradeChange = (studentId, field, value) => {
    setGradeInputs((prev) => ({
      ...prev,
      [studentId]: {
        ...prev[studentId],
        [field]: value
      }
    }));
  };

  const handleSaveGrade = async (studentId) => {
    const input = gradeInputs[studentId] || {};

    try {
      await api.put(`/courses/${id}/grade/${studentId}`, {
        grade: input.grade,
        feedback: input.feedback
      });
      alert('Grade saved');
      fetchCourse();
    } catch (error) {
      alert('Could not save grade: ' + error.response?.data?.message);
    }
  };

  const handleEnroll = async () => {
    try {
      await api.post(`/courses/${id}/enroll`);
      alert('Enrollment request submitted!');
      fetchCourse();
    } catch (error) {
      alert('Enrollment failed: ' + error.response?.data?.message);
    }
  };

  const handleApprove = async (studentId) => {
    try {
      await api.put(`/courses/${id}/approve/${studentId}`);
      alert('Enrollment approved');
      fetchCourse();
    } catch (error) {
      alert('Approval failed: ' + error.response?.data?.message);
    }
  };

  const handleAddMaterial = async () => {
    if (!newMaterial.title || !newMaterial.type) {
      alert('Title and type are required');
      return;
    }

    try {
      await api.post(`/courses/${id}/materials`, newMaterial);
      setNewMaterial({ title: '', type: 'video', url: '', content: '' });
      fetchCourse();
    } catch (error) {
      alert('Could not add material: ' + error.response?.data?.message);
    }
  };

  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Typography variant="h3" component="h1" gutterBottom>
          {course.title}
        </Typography>
        {(isInstructor || isAdmin) && (
          <Button variant="outlined" onClick={() => navigate(`/course/${id}/edit`)}>
            Edit Course
          </Button>
        )}
      </Box>

      <Typography variant="h5" color="textSecondary" gutterBottom>
        {course.category} • {course.level} • {course.duration} hours
      </Typography>
      
      <Typography variant="body1" paragraph>
        {course.description}
      </Typography>
      
      <Typography variant="h6">
        Instructor: {course.instructor.name}
      </Typography>
      
      <Typography variant="body2" sx={{ mb: 2 }}>
        Average Rating: {(course.averageRating || 0).toFixed(1)}/5 ({(course.ratings || []).length} reviews)
      </Typography>

      {!user && (
        <Typography sx={{ mt: 2 }}>Log in to enroll and rate this course.</Typography>
      )}

      {user && user.role === 'learner' && !isApproved && !isPending && !isInstructor && !isAdmin && (
        <Button variant="contained" onClick={handleEnroll} sx={{ mt: 2 }}>
          Enroll
        </Button>
      )}

      {user && isPending && (
        <Typography sx={{ mt: 2 }}>Your enrollment is pending approval.</Typography>
      )}

      {user && isApproved && (
        <Box sx={{ mt: 2 }}>
          <Typography>You are enrolled in this course.</Typography>
          <Typography variant="body2" color="textSecondary">
            Progress: {userEnrollment?.progress ?? 0}% completed
          </Typography>
        </Box>
      )}

      {user && isApproved && !isInstructor && !isAdmin && (
        <Box sx={{ mt: 4 }}>
          <Typography variant="h5" gutterBottom>
            Leave a Review
          </Typography>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, flexWrap: 'wrap' }}>
            <Rating
              name="course-rating"
              value={rating}
              onChange={(event, newValue) => setRating(newValue)}
            />
            <TextField
              label="Review"
              value={review}
              onChange={(e) => setReview(e.target.value)}
              multiline
              rows={2}
              sx={{ flex: 1, minWidth: 240 }}
            />
          </Box>
          <Button
            variant="contained"
            sx={{ mt: 2 }}
            onClick={handleRatingSubmit}
            disabled={!rating}
          >
            Submit Review
          </Button>
        </Box>
      )}

      {(isInstructor || isAdmin) && (
        <Box sx={{ mt: 4 }}>
          <Typography variant="h5" gutterBottom>
            Pending Enrollments
          </Typography>
          {pendingEnrollments.length === 0 ? (
            <Typography>No pending enrollment requests.</Typography>
          ) : (
            pendingEnrollments.map((enrollment) => (
              <Box key={enrollment.student._id} sx={{ mb: 2, p: 2, border: '1px solid #ccc', borderRadius: 1 }}>
                <Typography><strong>{enrollment.student.name}</strong> ({enrollment.student.email})</Typography>
                <Button
                  variant="contained"
                  size="small"
                  sx={{ mt: 1 }}
                  onClick={() => handleApprove(enrollment.student._id)}
                >
                  Approve
                </Button>
              </Box>
            ))
          )}
        </Box>
      )}

      {isInstructor || isAdmin ? (
        <Box sx={{ mt: 4 }}>
          <Typography variant="h5" gutterBottom>
            Add Course Material
          </Typography>
          <TextField
            label="Title"
            fullWidth
            value={newMaterial.title}
            onChange={(e) => setNewMaterial((prev) => ({ ...prev, title: e.target.value }))}
            sx={{ mb: 2 }}
          />
          <TextField
            label="Type"
            fullWidth
            value={newMaterial.type}
            onChange={(e) => setNewMaterial((prev) => ({ ...prev, type: e.target.value }))}
            sx={{ mb: 2 }}
          />
          <TextField
            label="URL"
            fullWidth
            value={newMaterial.url}
            onChange={(e) => setNewMaterial((prev) => ({ ...prev, url: e.target.value }))}
            sx={{ mb: 2 }}
          />
          <TextField
            label="Content"
            fullWidth
            multiline
            rows={3}
            value={newMaterial.content}
            onChange={(e) => setNewMaterial((prev) => ({ ...prev, content: e.target.value }))}
            sx={{ mb: 2 }}
          />
          <Button variant="contained" onClick={handleAddMaterial}>
            Add Material
          </Button>
        </Box>
      ) : null}

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Course Materials
      </Typography>
      
      <List>
        {(course.materials || []).map((material, index) => (
          <div key={index}>
            <ListItem>
              <ListItemText
                primary={material.title}
                secondary={`Type: ${material.type}`}
              />
              <Button variant="outlined" size="small" href={material.url} target="_blank">
                View
              </Button>
            </ListItem>
            {index < (course.materials || []).length - 1 && <Divider />}
          </div>
        ))}
      </List>

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Assignments
      </Typography>
      {course.materials?.filter((m) => m.type === 'assignment').length > 0 ? (
        <List>
          {course.materials
            .filter((m) => m.type === 'assignment')
            .map((assignment, index) => (
              <div key={index}>
                <ListItem>
                  <ListItemText
                    primary={assignment.title}
                    secondary={assignment.content || 'No description provided.'}
                  />
                </ListItem>
                {index < course.materials.filter((m) => m.type === 'assignment').length - 1 && <Divider />}
              </div>
            ))}
        </List>
      ) : (
        <Typography>No assignments have been added yet.</Typography>
      )}

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Grades
      </Typography>

      {isInstructor || isAdmin ? (
        <Box>
          <Typography sx={{ mb: 2 }}>
            Set grades for enrolled students.
          </Typography>
          {course.enrolledStudents
            .filter((s) => s.status === 'approved')
            .map((enrollment) => {
              const student = enrollment.student;
              const current = gradeInputs[student._id] || { grade: '', feedback: '' };
              return (
                <Box key={student._id} sx={{ mb: 2, p: 2, border: '1px solid #ccc', borderRadius: 1 }}>
                  <Typography><strong>{student.name}</strong> ({student.email})</Typography>
                  <TextField
                    label="Grade"
                    value={current.grade}
                    onChange={(e) => handleGradeChange(student._id, 'grade', e.target.value)}
                    sx={{ mt: 1, mr: 1, width: 150 }}
                  />
                  <TextField
                    label="Feedback"
                    value={current.feedback}
                    onChange={(e) => handleGradeChange(student._id, 'feedback', e.target.value)}
                    sx={{ mt: 1, mr: 1, flex: 1 }}
                  />
                  <Button
                    variant="contained"
                    size="small"
                    sx={{ mt: 1 }}
                    onClick={() => handleSaveGrade(student._id)}
                  >
                    Save Grade
                  </Button>
                </Box>
              );
            })}
        </Box>
      ) : (
        <Typography sx={{ mb: 2 }}>
          Your current grade: {course.grades?.find((g) => g.student._id === user?.id)?.grade || 'N/A'}
        </Typography>
      )}

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Lessons
      </Typography>

      {course.lessons && course.lessons.length > 0 ? (
        <List>
          {course.lessons.map((lesson, index) => {
            const isCompleted = completedLessons.some(
              (id) => id === lesson._id || id?.toString() === lesson._id
            );
            return (
              <div key={lesson._id || index}>
                <ListItem>
                  <FormControlLabel
                    control={
                      <Checkbox
                        checked={isCompleted}
                        onChange={() => handleToggleLesson(lesson)}
                        disabled={!canAccessLessons}
                      />
                    }
                    label={lesson.title}
                  />
                </ListItem>
                {lesson.content && (
                  <Typography sx={{ ml: 5, mb: 1 }} variant="body2" color="textSecondary">
                    {lesson.content}
                  </Typography>
                )}
                {index < course.lessons.length - 1 && <Divider />}
              </div>
            );
          })}
        </List>
      ) : (
        <Typography>No lessons have been added yet.</Typography>
      )}

      {canAccessLessons && (
        <Typography variant="body2" sx={{ mt: 1 }}>
          Check off lessons as you complete them to keep track of your progress.
        </Typography>
      )}

      {user && <CourseChat courseId={id} />}

      <Typography variant="h5" sx={{ mt: 4, mb: 2 }}>
        Reviews
      </Typography>
      
      <List>
        {(course.ratings || []).map((rating, index) => (
          <div key={index}>
            <ListItem>
              <ListItemText
                primary={`${rating.student.name} - ${rating.rating}/5`}
                secondary={rating.review}
              />
            </ListItem>
            {index < (course.ratings || []).length - 1 && <Divider />}
          </div>
        ))}
      </List>
    </Container>
  );
};

export default CourseDetails;